import PropTypes from 'prop-types';

export const ButtonGroupItemTypes = {
  title: PropTypes.string.isRequired,
  /**
   * @todo switch this to a CustomPropType.url.isRequired once we have a way of
   * sharing them between flow-web and UI lib
   */
  url: PropTypes.string.isRequired,
  icon: PropTypes.func.isRequired,
};

export const ButtonGroupTypes = {
  items: PropTypes.arrayOf(PropTypes.shape(ButtonGroupItemTypes).isRequired)
    .isRequired,
};
