import { Fragment } from 'react';

import {
  Wrapper,
  List,
  Item,
  Title,
  ItemIcon,
  Chevron,
} from './ButtonGroup.styles';
import { ButtonGroupTypes } from './ButtonGroup.types';

const ButtonGroup = ({ items }) => {
  if (!Array.isArray(items) || !items?.length) {
    return null;
  }

  return (
    <Wrapper>
      <List $itemCount={items.length}>
        {items.map(({ title, url, icon, target }, i) => (
          <li key={`item-${i}`}>
            <Item href={url} target={target}>
              <ItemIcon svg={icon} />
              <Title>
                {title.split(' ').map((part, j) => (
                  <Fragment key={`title-${j}`}>
                    <span>{part} </span>
                  </Fragment>
                ))}
              </Title>
              <Chevron />
            </Item>
          </li>
        ))}
      </List>
    </Wrapper>
  );
};

ButtonGroup.propTypes = ButtonGroupTypes;

export default ButtonGroup;
