import { styled, css } from 'styled-components';

import {
  BUTTON_SIZE_SMALL,
  BUTTON_SIZE_BASE,
} from '#components/Button/Button.constants';
import { Icon } from '#components/Icon';

import * as device from '#theme/devices';

import ChevronRightSVG from '#icons/chevron-right-solid-16.svg';

export const Wrapper = styled.div`
  display: block;
`;

export const List = styled.ul`
  --gap: 16px;
  --cols: 2;
  --max-width: 100%;
  --total-gap: calc(var(--gap) * (var(--cols) - 1));
  --item-width: calc((100% - var(--total-gap)) / var(--cols));
  display: flex;
  max-width: var(--max-width);
  flex-flow: row wrap;
  justify-content: center;
  gap: var(--gap);
  padding: 0;
  margin: 0 auto;
  list-style: none;

  > li {
    width: var(--item-width);
    flex: 0 1 var(--item-width);
    padding: 0;
    margin: 0;
  }

  @media ${device.tablet} {
    --cols: 3;
    --max-width: 100%;

    ${({ $itemCount }) =>
      // if there are 4 or 2 items, we want to make the list 2 columns wide
      $itemCount === 4 || $itemCount === 2
        ? css`
            --cols: 2;
            --max-width: calc(100% / 3 * 2);
          `
        : ''}
  }
`;

/*
  we have to wrap each individual word in a span to allow us to truncate that
  word if the button is not wide enough. We have to do this at the word level as
  the buttons can support 2 lines of text. This then means that we have to
  emulate the spacing between words with column gap between the spans.
*/
export const Title = styled.div`
  display: flex;
  min-width: 0;
  flex-flow: row wrap;
  column-gap: ${({ theme }) => theme.dimension.text.spaceWidthEm}em;
  line-height: inherit;

  span {
    display: inline-block;
    overflow: hidden;
    max-width: 100%;
    text-overflow: ellipsis;
  }
`;

export const ItemIcon = styled(Icon).attrs({
  size: BUTTON_SIZE_BASE,
})``;

export const Chevron = styled(Icon).attrs({
  svg: ChevronRightSVG,
  size: BUTTON_SIZE_SMALL,
})`
  display: block;
  margin-left: auto;
  color: currentColor;
`;

/** @todo: replace with correct semantic name for the color and bg */
export const Item = styled.a`
  --color: ${({ theme }) => theme.color.ink.base};
  --bg: ${({ theme }) => theme.color.canvas.base};
  --hover-color: var(--bg);
  --hover-bg: var(--color);
  display: flex;
  height: ${({ theme }) => theme.dimension.btn.height}px;
  box-sizing: border-box;
  flex-flow: row nowrap;
  align-items: center;
  gap: ${({ theme }) => theme.dimension.btn.iconSpacing}px;
  padding: 0 ${({ theme }) => theme.spacing.x1}px;
  border: 1px solid ${({ theme }) => theme.color.divider.light};
  border-radius: ${({ theme }) => theme.dimension.btn.borderRadius}px;
  background-color: var(--bg);
  color: var(--color);
  font: ${({ theme }) => theme.textStyle.buttonGroup.base};
  transition: ${({ theme }) => theme.transition.button};

  &:hover,
  &:active {
    border-color: var(--hover-bg);
    background-color: var(--hover-bg);
    color: var(--hover-color);
  }

  ${ItemIcon}, ${Chevron} {
    flex-shrink: 0;
  }
`;
